What JavaScript functions can be used to create an interactive map that displays the locations of littering incidents and promotes community involvement in cleaning up public areas?
[JavaScript code]:
var map;
var markers = [];
function initMap() {
 map = new google.maps.Map(document.getElementById('map'), {
 center: {lat: 37.7749, lng: -122.4194},
 zoom: 12
 });

 // Add markers for littering incidents
 addMarkers();

 // Add event listener for when a marker is clicked
 map.addListener('click', function(event) {
 // Add new marker at clicked location
 var marker = new google.maps.Marker({
 position: event.latLng,
 map: map
 });

 // Add marker to list of markers
 markers.push(marker);

 // Prompt user to enter details about littering incident
 var description = prompt('Please enter a brief description of the littering incident:');

 // Create info window for new marker
 var infowindow = new google.maps.InfoWindow({
 content: description
 });

 // Open info window when marker is clicked
 marker.addListener('click', function() {
 infowindow.open(map, marker);
 });
 });
}
function addMarkers() {
 // Loop through array of littering incidents and add markers
 for (var i = 0; i < litteringIncidents.length; i++) {
 var marker = new google.maps.Marker({
 position: {lat: litteringIncidents[i].lat, lng: litteringIncidents[i].lng},
 map: map
 });

 // Create info window for marker
 var infowindow = new google.maps.InfoWindow({
 content: litteringIncidents[i].description
 });

 // Add event listener to open info window when marker is clicked
 marker.addListener('click', function() {
 infowindow.open(map, marker);
 });

 // Add marker to list of markers
 markers.push(marker);
 }
}
