What Go code can be used to retrieve and display nutritional information for a list of healthy foods on an HTML page?
Here's an example Go code snippet that can be used to retrieve nutritional information for a list of foods and display it on an HTML page:
package main
import (
 "encoding/json"
 "fmt"
 "io/ioutil"
 "net/http"
)
type Nutrient struct {
 Name string `json:"name"`
 Unit string `json:"unit"`
 Value float64 `json:"value"`
 Percentage float64 `json:"percentDailyValue"`
}
type Food struct {
 Name string `json:"name"`
 Nutrients []Nutrient `json:"nutrients"`
}
func main() {
 foods := []string{"spinach", "blueberries", "salmon", "avocado", "almonds"}
 fmt.Println("")
 for _, food := range foods {
 resp, err := http.Get(fmt.Sprintf("https://api.nal.usda.gov/fdc/v1/foods/search?api_key=API_KEY&query=%s", food))
 if err != nil {
 panic(err)
 }
 defer resp.Body.Close()
 body, err := ioutil.ReadAll(resp.Body)
 if err != nil {
 panic(err)
 }
 var data struct {
 Foods []Food `json:"foods"`
 }
 err = json.Unmarshal(body, &data)
 if err != nil {
 panic(err)
 }
 if len(data.Foods) > 0 {
 fmt.Printf("* %s
	", data.Foods[0].Name)
	 for _, nutrient := range data.Foods[0].Nutrients {
	 fmt.Printf("+ %s: %g %s
	", nutrient.Name, nutrient.Value, nutrient.Unit)
	 }
	 fmt.Println("
")
 }
 }
 fmt.Println("
")
}
This code uses the USDA FoodData Central API to retrieve nutritional information for a list of foods, and then formats the information as an HTML list. You can customize the list of foods by modifying the `foods` slice at the beginning of the `main` function.

